class KnowledgeGraph:
    def __init__(self):
        self._triples = set()  # (subject, relation, obj)
        self._forward = {}    # subject -> [(relation, obj)]
        self._backward = {}   # obj -> [(relation, subject)]
        self._entities = set()

    def add_triple(self, subject: str, relation: str, obj: str):
        triple = (subject, relation, obj)
        if triple in self._triples:
            return
        self._triples.add(triple)
        self._entities.update([subject, obj])
        self._forward.setdefault(subject, []).append((relation, obj))
        self._backward.setdefault(obj, []).append((relation, subject))

    def neighbors(self, entity: str) -> list:
        return list(self._forward.get(entity, []))

    def reverse_neighbors(self, entity: str) -> list:
        return list(self._backward.get(entity, []))

    def get_relations(self, subject: str, obj: str) -> list:
        return [r for r, o in self._forward.get(subject, []) if o == obj]

    def entity_count(self) -> int:
        return len(self._entities)
